import { motion } from "framer-motion"

import { useRef, useEffect } from "react"
import Typed from "typed.js"
import Techstack from "./Techstack";
import { useState } from "react";

export default function HeroSection() {
    const [isLoaded, setIsLoaded] = useState(false)
    const el = useRef()
    useEffect(() => {
        // Initialize Typed.js after a delay
        const timer = setTimeout(() => {
            const typed = new Typed(el.current, {
                strings: ["I develop front-end.", 'I build scalable UIs.', "I solve problems."],
                typeSpeed: 50,
                backSpeed: 50,
                loop: true,
                backDelay: 3000,
                smartBackspace: true,
            });

            return () => {
                typed.destroy(); //settimeout returns typed so it can be destroyde
            };
        }, 1000);

        return () => {
            clearTimeout(timer);
        };
    }, []);

    return (
        <section className="h-screen flex items-center">
            <div>
                <div className='flex lg:flex-col-reverse items-center md:mt-14'>
                    <div className='w-1/2 lg:w-full'>
                        <motion.h1 initial={{ opacity: 0 }} animate={{ opacity: 1 }} transition={{ delay: .5 }} className="font-mono text-l text-slate-400">Hi, my name is</motion.h1>
                        <motion.h1 initial={{ opacity: 0 }} animate={{ opacity: 1 }} transition={{ delay: .7 }} className='sm:text-5xl pb-2 mb-2 text-slate-200 font-semibold shadow-sm text-6xl font-inter whitespace-nowrap'>Baaz Cheema.</motion.h1>
                        <motion.div initial={{ opacity: 0 }} animate={{ opacity: 1 }} transition={{ delay: .9 }} className="mb-5">
                            <motion.h1 ref={el} id="bef" className="-z-10  inline  text-amber-300 pb-2  shadow-sm font-mono text-3xl sm:text-2xl"></motion.h1>
                        </motion.div>
                        <motion.p initial={{ opacity: 0 }} animate={{ opacity: 1 }} transition={{ delay: 1.1 }} className='font-inter  sm:text-lg text-slate-400 inline-block text-xl'>I am an aspiring react developer based in Gujrat, Pakistan. I enjoy learning new technologies and building user-friendly interfaces.</motion.p>
                        <motion.div initial={{ opacity: 0 }} animate={{ opacity: 1 }} transition={{ delay: 1.4, duration: 1 }} className='mt-6 inline-block'>

                            <a href="https://drive.google.com/file/d/1imFeC-n4tnGMyuCbc8NAXxKdH9FBueDb/view?usp=sharing" target="_blank ">
                                <motion.button
                                    whileHover={{
                                        y: -5,
                                        boxShadow: '0px 0.5em 0.5em -0.4em rgb(252, 211, 77)',
                                        borderColor: 'rgb(252, 211, 77)',
                                        color: 'rgb(252, 211, 77)'
                                    }}
                                    className="py-3 text-slate-200 px-8 border-red-500 border-2 font-mono inline-flex items-center gap-3">
                                    <i className='bx bx-cloud-download text-2xl' ></i> Resume
                                </motion.button></a>

                        </motion.div>
                    </div>
                    <motion.div className="relative w-1/2 lg:w-10/12 lg:mb-10   flex justify-center pl-20 lg:pl-0 lg:justify-center -z-10">

                        <motion.img rel="preload" onLoad={() => setIsLoaded(true)} initial={{ opacity: 0, scale: 1.1 }} animate={{ opacity: 1, scale: 1 }} transition={{ duration: .7 }} className="w-96 ml-auto lg:ml-0" src="data:image/webp;base64," alt="" />


                    </motion.div>
                    <div>
                    </div>
                </div>
                {/* <motion.div className="lg:hidden">
                    <Techstack delayVal={1.5} />
                </motion.div> */}
            </div>
        </section >
    )
}